+/// `mount(source, target, filesystemtype, mountflags, data)` — mount filesystem.
+#[inline]
+#[allow(unsafe_code)]
+pub unsafe fn sys_mount(
+    source: *const u8,
+    target: *const u8,
+    filesystemtype: *const u8,
+    mountflags: usize,
+    data: *const u8,
+) -> Result<(), i32> {
+    let ret = unsafe {
+        raw::syscall5(
+            SYS_MOUNT,
+            source as usize,
+            target as usize,
+            filesystemtype as usize,
+            mountflags,
+            data as usize,
+        )
+    };
+    syscall_result(ret).map(|_| ())
+}
